mapper.update:
UPDATE ARTITED
   SET WATER_COST = #{waterCost},
       WATER_VAL = #{waterVal},
       WATER_SUM = (
           SELECT COALESCE(SUM(COALESCE(T1.WATER_VOL, 0)), 0)
             FROM ARTITEC T1
            WHERE T1.ITEM_ID = #{itemId}
              AND T1.SEQ = #{seq}
       ),
       CHG_USER_ID = #{chgUserId},
       CHG_DATE = NOW()
 WHERE ITEM_ID = #{itemId}
   AND SEQ = #{seq}

